document.addEventListener("DOMContentLoaded",()=>{"use strict";const e=document.querySelectorAll(".needs-validation");Array.from(e).forEach(e=>{e.addEventListener("submit",t=>{if(e.checkValidity()){t.preventDefault();const s=e.querySelector('button[type="submit"]'),a=s.innerHTML;s.innerHTML='<i class="fa-solid fa-circle-check"></i> Processing...',s.disabled=!0,setTimeout(()=>{s.innerHTML='<i class="fa-solid fa-circle-check"></i> Success!',s.classList.remove("btn-primary-custom"),s.classList.add("btn-success"),setTimeout(()=>{s.innerHTML=a,s.classList.add("btn-primary-custom"),s.classList.remove("btn-success"),s.disabled=!1,e.reset(),e.classList.remove("was-validated")},3e3)},1500)}else t.preventDefault(),t.stopPropagation();e.classList.add("was-validated")},!1)});document.querySelectorAll('input[type="email"]').forEach(e=>{e.addEventListener("input",()=>{e.validity.typeMismatch?e.setCustomValidity("Please enter a valid email address."):e.setCustomValidity("")})});const t=document.getElementById("signupPassword"),s=document.getElementById("signupConfirmPassword");t&&s&&(s.addEventListener("input",()=>{s.value!==t.value?s.setCustomValidity("Passwords do not match."):s.setCustomValidity("")}),t.addEventListener("input",()=>{""!==s.value&&(s.value!==t.value?s.setCustomValidity("Passwords do not match."):s.setCustomValidity(""))}))});